import React, { useEffect, useState } from 'react';
import api from '../api';
import ProductCard from '../components/ProductCard';
import CategoryFilter from '../components/CategoryFilter';

const Home = () => {
  const [products, setProducts] = useState([]);
  const [category, setCategory] = useState('ALL');
  const [keyword, setKeyword] = useState('');

  const fetchProducts = async () => {
    try {
      if (keyword) {
        const res = await api.get('products/search', { params: { keyword } });
        setProducts(res.data);
        return;
      }

      if (category !== 'ALL') {
        const res = await api.get(`products/category/${category}`);
        setProducts(res.data);
        return;
      }

      const res = await api.get('products');
      setProducts(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, [category, keyword]);

  return (
    <div>
      <h2>Marketplace</h2>
      <div>
        <input type="text" value={keyword} placeholder="Search products" onChange={(e) => setKeyword(e.target.value)} />
        <CategoryFilter value={category} onChange={setCategory} />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: 12 }}>
        {products.map((product) => <ProductCard key={product.id} product={product} onRefresh={fetchProducts} />)}
      </div>
    </div>
  );
};

export default Home;
